import{_ as p}from"./plugin-vue_export-helper-c27b6911.js";import{o as e,c as _,f as t}from"./app-4ea9d5e7.js";const a={},c=t('<h1 id="_19-切一刀的隐喻" tabindex="-1"><a class="header-anchor" href="#_19-切一刀的隐喻" aria-hidden="true">#</a> #19 切一刀的隐喻</h1><p>假设有一个蛋糕，里面有黑色（亏钱部分），白色（赚钱部分）。那么我基于数据拟合出了一个规律，也是一种刀子的切割方法。最终我肯定想要的是白色占比足够大。这就是对于Chilun增加筛选条件的底层逻辑。 不停的切割，每次切割黑色占比多的舍弃。这样总体而言，白色的占比就可以不停的增加。</p><p>这个蛋糕会越来越小，但是其白色蛋糕的占比会越来越多。</p><p>这就是切一刀的隐喻。</p><p>天尊定理，定于一尊之后，就不再参与俗世。这个理，是世界的法则。</p><p>但是各方的强者，虽然做不到逆转天地之理，但也可以在自己的小世界，构建出理上之理。</p><p>理上之理，有更加适用的，更强力的生效空间。这个更强力的空间，可以用上面的刀子切蛋糕的方式，一刀刀切割出来。</p><p>....</p><p>All Last。</p><p>打分是一种截面上的多选择对比，按照一定基准对Choice进行比较。</p><p>筛选是一种空间上的剔除一些选择，将一些必然鸡肋的予以剔除。</p><p>从这个角度，</p><p>当你A股可以通过量化进行，炒美股就不再有价值。主观择股就要完全剔除出决策池。听消息花费的精力就要完全节省下来。</p><p>当你可以通过信用贷进行扩表，信用卡就完全是累赘。根本不值得花时间研究那几个积分，每个月手动还款完全浪费精力。</p><p>当你通过资本赚钱，多房产策略就一定首先被抛弃。收租、装修、扯皮等均需要消耗精力，高昂的维护成本就可以省下。</p><p>那一刀切去的部分里，不是没有白色。而是白色占比比较低。</p>',16),o=[c];function r(n,s){return e(),_("div",null,o)}const l=p(a,[["render",r],["__file","18 切一刀的隐喻.html.vue"]]);export{l as default};
